import { BrowserRouter, Routes, Route } from "react-router-dom";
import { NewStudyPlace } from "./NewStudyPlace";
import { StudyPlacesPage } from "./StudyPlacesPage";
export function App() {
  return (
    <BrowserRouter>
    <Routes>
      <Route path="/" element={
        <div>This will be our main page</div>
        }
      />
      <Route
        path="/new-study-place"
        element={
          <div className="new-study-page">
            <div className="app">
              <h1>New study place Form</h1>
              <NewStudyPlace />
            </div>
          </div>
        }
      />

        <Route
        path="/study-places"
        element={
          <div className="study-place">
            <div className="app">
              <h1>Filters</h1>
              <StudyPlacesPage />
            </div>
          </div>
        }
      />

    </Routes>
  </BrowserRouter>

  );
}

